#include <stdio.h>
#define MOD 1000000007
int main() {
    int T, N, D;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &D);
        long long ans = 0;
        for (int i = 1; i <= N; i++) {
            long long ways = 1;
            for (int j = 0; j < i; j++) {
                ways = (ways * (D + j)) % MOD;
            }
            ans = (ans + ways) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

