import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int D = sc.nextInt();
            long ans = 0;
            for (int i = 1; i <= N; i++) {
                long ways = 1;
                for (int j = 0; j < i; j++) {
                    ways = (ways * (D + j)) % 1000000007;
                }
                ans = (ans + ways) % 1000000007;
            }
            System.out.println(ans);
        }
    }
}

